12	const PROCESSING_FEE = 5;
13	// Base premiums for main (non-component) items. Components such as runes are
14	// priced separately via componentBasePremium and never read from this table.
15	const BASE_PREMIUMS: Record<string, number> = {
16	  sword: 100,
17	  amulet: 60,
18	  staff: 80,
19	  potion: 40,
20	};
21	const FIRST_INSURANCE_RATE = 0.1;
22	const CURSE_SURCHARGE_RATE = 0.5;
23	const HIGH_ENCHANTMENT_RATE = 0.3;
24	const HIGH_ENCHANTMENT_THRESHOLD = 5;
25	
26	// A main item's premium: its base premium plus item-specific surcharges, each
27	// applied additively to the base (first insurance always; curse if cursed;
28	// high-enchantment if enchantment meets the threshold).
29	const mainItemPremium = (item: Item): number => {
30	  const base = BASE_PREMIUMS[item.type];
31	  const curseRate = item.cursed ? CURSE_SURCHARGE_RATE : 0;
32	  const highEnchantmentRate =
33	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
34	      ? HIGH_ENCHANTMENT_RATE
35	      : 0;
36	  return base * (1 + FIRST_INSURANCE_RATE + curseRate + highEnchantmentRate);
37	};
38	
39	const COMPONENT_TYPES = ["rune", "moonstone"];
40	const COMPONENT_BASE_PREMIUM = 25;
41	const COMPONENT_BLOCK_SIZE = 3;
42	const COMPONENT_BLOCK_PREMIUM = 60;
43	
44	const isComponent = (item: Item): boolean =>
45	  COMPONENT_TYPES.includes(item.type);
46	
47	// Base premium for `count` alike components: a block premium applies only for
48	// exactly one block's worth (3) of components; otherwise each is priced individually.
49	const componentBasePremium = (count: number): number => {
50	  if (count === COMPONENT_BLOCK_SIZE) return COMPONENT_BLOCK_PREMIUM;
51	  return count * COMPONENT_BASE_PREMIUM;
52	};
53	
54	const countByType = (items: Item[]): Map<string, number> => {
55	  const counts = new Map<string, number>();
56	  for (const item of items) {
57	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
58	  }
59	  return counts;
60	};
61	
62	// The block rule is per-type ("alike" = same type), so price each type's count
63	// independently and sum across types.
64	const componentItemsBase = (componentItems: Item[]): number =>
65	  [...countByType(componentItems).values()].reduce(
66	    (base, count) => base + withFirstInsurance(componentBasePremium(count)),
67	    0,
68	  );
69	
70	// Every item is treated as first insurance today, so the surcharge is applied
71	// uniformly to each base premium, using the same additive rate as main items
72	// (single source of truth for first insurance).
73	const withFirstInsurance = (basePremium: number): number =>
74	  basePremium * (1 + FIRST_INSURANCE_RATE);
75	
76	// Round up in MHPCO's favour, guarding against floating-point noise
77	// (e.g. 197.50000000001 should still round to 198, not 199).
78	const roundUpInMHPCOFavor = (amount: number): number =>
79	  Math.ceil(Number(amount.toFixed(6)));
80	
81	export const quote = (
82	  items: Item[],
83	  customer: Customer,
84	  contractIndex: number,
85	): number => {
86	  const mainItems = items.filter((item) => !isComponent(item));
87	  const componentItems = items.filter((item) => isComponent(item));
88	
89	  const mainBase = mainItems.reduce(
90	    (sum, item) => sum + mainItemPremium(item),
91	    0,
92	  );
93	  const componentBase = componentItemsBase(componentItems);
94	
95	  return roundUpInMHPCOFavor(mainBase + componentBase + PROCESSING_FEE);
96	};
97	
98	export const claim = (): number => {
99	  return undefined as unknown as number;
100	};
